17a37610-bbb1-487c-a9d4-a017f71544b2	156c8c4f-4aae-4bff-8f29-4ac24d4805f5	our-story	Our Story	published		Why we started delivering groceries.	f	[{"id": "6758f0a6-10c3-4303-a27f-ac30409a290a", "type": "hero", "config": {"theme": "dark", "heading": "Groceries, minus the queue", "variant": "banner", "cta_href": "/shop", "alignment": "left", "cta_label": "Shop fresh", "image_url": "/themes/basket/hero.webp", "video_url": "", "background": "#fae3c1", "badge_text": "Our story", "subheading": "We do the market run for you — sourced this morning, at your door by dinner."}, "enabled": true}, {"id": "624bc238-4c60-43bc-8480-d7bfc68e6266", "type": "rich_text", "style": {"padding_y": "sm"}, "config": {"html": "<h2>It started with a bad tomato</h2><p>Fresh food shouldn't cost you an hour of your evening — or arrive tired and bruised. So we built a store that shops the way we'd want someone to shop for us: straight from local farms and mills every morning, hand-checked, and delivered before dinner.</p><p>No warehouses full of week-old produce. No mystery supply chains. Just good food, moving fast.</p><p><strong>If it isn't fresh enough for our own kitchens, it doesn't go in yours.</strong></p>", "width": "contained"}, "enabled": true}, {"id": "27c6702d-fa86-4606-b643-319d82850baf", "type": "usp_bar", "style": {"width": "full", "padding_y": "md", "background": "#101b33"}, "config": {"items": [{"icon": "leaf", "title": "Sourced daily", "subtitle": "From local farms & mills"}, {"icon": "truck", "title": "Delivered fast", "subtitle": "At your door by dinner"}, {"icon": "badge-check", "title": "Hand-checked", "subtitle": "Every single order"}, {"icon": "heart", "title": "Kitchen-tested", "subtitle": "We eat what we sell"}], "theme": "light"}, "enabled": true}, {"id": "c70bc885-d4d6-4026-9e35-0ee21c657647", "type": "hero", "config": {"theme": "light", "heading": "Come taste the difference", "variant": "minimal", "cta_href": "/shop", "alignment": "center", "cta_label": "Start shopping",