1e70491c-a79f-4717-aa7f-7a2b81f21d7a	d657f87a-2caa-43fa-8978-1f78bb62abe8	faqs	FAQs	published		Answers to common questions.	f	[{"id": "df7f52e7-666b-40a6-9b41-ffd7713b4121", "type": "faq_accordion", "style": {"padding_y": "md"}, "config": {"items": [{"answer": "We source from local farms and mills every morning, so most produce reaches you within a day of harvest. If anything isn't up to standard, we'll replace it free.", "category": "Orders", "question": "How fresh is the produce, really?"}, {"answer": "We deliver every day, 8am–9pm. Orders placed before 4pm arrive the same day; everything else arrives the next morning.", "category": "Delivery", "question": "What are your delivery times?"}, {"answer": "Tell us within 24 hours and we'll refund or replace it — no photos, no forms.", "category": "Returns", "question": "What if something arrives damaged?"}, {"answer": "No minimum. Orders over ₹499 ship free; below that a flat ₹29 delivery fee applies.", "category": "Orders", "question": "Is there a minimum order value?"}, {"answer": "Cards, UPI, net banking and cash on delivery — pick whatever's easiest at checkout.", "category": "Payments", "question": "Which payment methods do you accept?"}, {"answer": "Unopened packaged items can be returned within 7 days. Fresh items can be handed back at the doorstep on delivery.", "category": "Returns", "question": "Can I return packaged goods?"}], "heading": "Frequently asked questions", "subheading": "Delivery, returns, freshness — everything you might wonder about.", "show_filters": true}, "enabled": true}]	[{"id": "df7f52e7-666b-40a6-9b41-ffd7713b4121", "type": "faq_accordion", "style": {"padding_y": "md"}, "config": {"items": [{"answer": "We source from local farms and mills every morning, so most produce reaches you within a day of harvest. If anything isn't up to standard, we'll replace it free.", "category": "Orders", "question": "How fresh is the produce, really?"}, {"answer": "We deliver every day, 8am–9pm. Orders placed before 4pm arrive the same day; everything else arrives the next morning.", "category": "Delivery", "question": "What are your delivery times?"}, {"answer": "Tell us within 24 hours and we'll refund or replace it — no photos, no forms.", "category": "Returns", "question": "What if something arrives damaged?"}, {"answer": "No minimum. Orders over ₹499 ship free; below that a flat ₹29 delivery fee applies.", "category": "Orders", "question": "Is there a minimum order value?"}, {"answer": "Cards, UPI, net banking and cash on delivery — pick whatever's easiest at checkout.", "category": "Payments", "question": "Which payment methods do you accept?"}, {"answer": "Unopened packaged items can be returned within 7 days. Fresh items can be handed back at the doorstep on delivery.", "category": "Returns", "question": "Can I return packaged goods?"}], "heading": "Frequently asked questions", "subheading": "Delivery, returns, freshness — everything you might wonder about.", "show_filters": true}, "enabled": true}]	2026-07-13 20:26:17.313+00	634781f9-05e9-44f0-b41c-fd654679459d	634781f9-05e9-44f0-b41c-fd654679459d	2026-07-13 20:26:17.449651+00	2026-07-13 20:26:17.449651+00
a809aa84-37ac-4198-a9cb-6a739f068390	d657f87a-2caa-43fa-8978-1f78bb62abe8	delivery-returns	Delivery & Returns	published		Delivery slots, coverage and our returns promise.	f	[{"id": "506dfaab-e235-4962-87db-b292574ee331", "type": "rich_text", "config": {"html": "<h2>Delivery &amp; returns</h2><h3>Delivery</h3><p>We deliver every day, 8am–9pm. Orders placed before 4pm arrive the same day; everything else arrives next morning.</p><h3>Returns</h3><p>Fresh items can be returned at the doorstep. Packaged goods can be returned unopened within 7 days.</p>", "width": "contained"}, "enabled": true}]	[{"id": "506dfaab-e235-4962-87db-b292574ee331", "type": "rich_text", "config": {"html": "<h2>Delivery &amp; returns</h2><h3>Delivery</h3><p>We deliver every day, 8am–9pm. Orders placed before 4pm arrive the same day; everything else arrives next morning.</p><h3>Returns</h3><p>Fresh items can be returned at the doorstep. Packaged goods can be returned unopened within 7 days.</p>", "width": "contained"}, "enabled": true}]	2026-07-13 20:26:17.578+00	634781f9-05e9-44f0-b41c-fd654679459d	634781f9-05e9-44f0-b41c-fd654679459d	2026-07-13 20:26:17.708969+00	2026-07-13 20:26:17.708969+00
